import{_ as i,o as a,c as o,ag as l}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Conduit (Tubería Eléctrica)","description":"","frontmatter":{},"headers":[],"relativePath":"es/cables/installation/conduit.md","filePath":"es/cables/installation/conduit.md"}'),n={name:"es/cables/installation/conduit.md"};function r(t,e,s,c,d,u){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="conduit-tuberia-electrica" tabindex="-1">Conduit (Tubería Eléctrica) <a class="header-anchor" href="#conduit-tuberia-electrica" aria-label="Permalink to &quot;Conduit (Tubería Eléctrica)&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción General <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción General&quot;">​</a></h2><p>El conduit es un sistema de protección utilizado para canalizar y resguardar cables eléctricos en instalaciones industriales. Consiste en tubos o canalizaciones que encierran los cables, proporcionando protección mecánica y aislamiento del entorno.</p><p>El conduit es ampliamente utilizado en entornos industriales donde los cables están expuestos a daños físicos, condiciones severas o requieren una instalación ordenada.</p><hr><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Los sistemas de conduit se utilizan para:</p><ul><li>Proteger cables contra daños mecánicos</li><li>Aislar cables de condiciones ambientales (humedad, polvo, químicos)</li><li>Proporcionar una canalización estructurada y ordenada</li><li>Mejorar la seguridad al encapsular conductores energizados</li><li>Facilitar mantenimiento y reemplazo futuro de cables</li></ul><hr><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><p>Los cables se instalan dentro de canalizaciones (conduit), que actúan como una barrera física entre el cable y el entorno.</p><p>El conduit:</p><ul><li>Evita la exposición directa a elementos externos</li><li>Contiene y organiza las rutas de cableado</li><li>Reduce el esfuerzo mecánico sobre los cables</li></ul><p>Sin embargo, al encerrar los cables también se afecta la disipación de calor, lo cual debe considerarse en el dimensionamiento.</p><hr><h2 id="tipos-comunes-de-conduit" tabindex="-1">Tipos Comunes de Conduit <a class="header-anchor" href="#tipos-comunes-de-conduit" aria-label="Permalink to &quot;Tipos Comunes de Conduit&quot;">​</a></h2><h3 id="conduit-metalico-rigido-rmc" tabindex="-1">Conduit Metálico Rígido (RMC) <a class="header-anchor" href="#conduit-metalico-rigido-rmc" aria-label="Permalink to &quot;Conduit Metálico Rígido (RMC)&quot;">​</a></h3><ul><li>Fabricado en acero o aluminio</li><li>Alta resistencia mecánica</li><li>Adecuado para ambientes severos</li></ul><p><strong>Aplicaciones:</strong></p><ul><li>Instalaciones industriales pesadas</li><li>Áreas con alto riesgo de impacto</li></ul><hr><h3 id="tuberia-metalica-electrica-emt" tabindex="-1">Tubería Metálica Eléctrica (EMT) <a class="header-anchor" href="#tuberia-metalica-electrica-emt" aria-label="Permalink to &quot;Tubería Metálica Eléctrica (EMT)&quot;">​</a></h3><ul><li>Conduit metálico de pared delgada</li><li>Más ligero y fácil de instalar que el RMC</li></ul><p><strong>Aplicaciones:</strong></p><ul><li>Instalaciones en interiores</li><li>Entornos comerciales e industriales ligeros</li></ul><hr><h3 id="conduit-de-pvc" tabindex="-1">Conduit de PVC <a class="header-anchor" href="#conduit-de-pvc" aria-label="Permalink to &quot;Conduit de PVC&quot;">​</a></h3><ul><li>No metálico y resistente a la corrosión</li><li>Ligero y económico</li></ul><p><strong>Aplicaciones:</strong></p><ul><li>Instalaciones subterráneas</li><li>Ambientes corrosivos</li></ul><hr><h3 id="conduit-flexible" tabindex="-1">Conduit Flexible <a class="header-anchor" href="#conduit-flexible" aria-label="Permalink to &quot;Conduit Flexible&quot;">​</a></h3><ul><li>Fabricado en metal o plástico flexible</li><li>Permite movimiento y absorbe vibraciones</li></ul><p><strong>Aplicaciones:</strong></p><ul><li>Conexión a motores y equipos en movimiento</li><li>Áreas donde se requiere flexibilidad</li></ul><hr><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>El conduit se utiliza en:</p><ul><li>Instalaciones industriales y plantas</li><li>Cableado externo de tableros de control</li><li>Instalaciones exteriores y subterráneas</li><li>Ambientes peligrosos o corrosivos</li></ul><hr><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><p>Al seleccionar conduit:</p><ul><li><strong>Protección mecánica:</strong> nivel de resistencia requerido</li><li><strong>Condiciones ambientales:</strong> humedad, químicos, temperatura</li><li><strong>Necesidad de flexibilidad:</strong> instalaciones fijas o móviles</li><li><strong>Resistencia a la corrosión:</strong> especialmente en ambientes agresivos</li><li><strong>Complejidad de instalación:</strong> facilidad de ruteo y montaje</li><li><strong>Disipación térmica:</strong> cables encerrados pueden requerir desclasificación (derating)</li></ul><hr><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>El conduit mejora la protección, pero reduce la disipación térmica, afectando la ampacidad del cable.</li><li>Sobrecargar el conduit dificulta la instalación y puede provocar sobrecalentamiento.</li><li>Un sellado adecuado es esencial en ambientes exteriores o peligrosos.</li><li>El conduit flexible debe utilizarse donde exista vibración o movimiento.</li><li>Los sistemas de conduit deben planearse considerando mantenimiento y expansión futura.</li></ul>',46)])])}const b=i(n,[["render",r]]);export{m as __pageData,b as default};
